package com.petclinic.clinic;

import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.context.TestPropertySource;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.Optional;

import static org.assertj.core.api.Assertions.assertThat;

@SpringBootTest
@TestPropertySource(locations = "classpath:application-test.properties")
@Transactional
public class ClinicServiceTest {

    @Autowired
    private ClinicService clinicService;

    @Autowired
    private ClinicRepository clinicRepository;

    @Test
    public void shouldRetrieveAllClinics() {
        // Given
        Clinic clinic1 = new Clinic("City Vet", "123 Main St", "555-1234");
        Clinic clinic2 = new Clinic("Pet Care Center", "456 Oak Ave", "555-5678");
        clinicRepository.save(clinic1);
        clinicRepository.save(clinic2);

        // When
        List<Clinic> clinics = clinicService.findAllClinics();

        // Then
        assertThat(clinics).hasSize(2);
        assertThat(clinics).extracting(Clinic::getName)
                .containsExactlyInAnyOrder("City Vet", "Pet Care Center");
    }

    @Test
    public void shouldFindClinicById() {
        // Given
        Clinic clinic = new Clinic("Animal Hospital", "789 Pine St", "555-9999");
        Clinic savedClinic = clinicRepository.save(clinic);

        // When
        Optional<Clinic> foundClinic = clinicService.findClinicById(savedClinic.getId());

        // Then
        assertThat(foundClinic).isPresent();
        assertThat(foundClinic.get().getName()).isEqualTo("Animal Hospital");
        assertThat(foundClinic.get().getAddress()).isEqualTo("789 Pine St");
        assertThat(foundClinic.get().getPhone()).isEqualTo("555-9999");
    }

    @Test
    public void shouldReturnEmptyWhenClinicNotFound() {
        // When
        Optional<Clinic> foundClinic = clinicService.findClinicById(999L);

        // Then
        assertThat(foundClinic).isEmpty();
    }
}

