package com.petclinic.pet;

import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/pets")
public class PetController {

    private final PetService petService;

    public PetController(PetService petService) {
        this.petService = petService;
    }

    @GetMapping("/{id}")
    public ResponseEntity<Pet> getPet(@PathVariable Long id) {
        return ResponseEntity.ok(petService.findById(id));
    }

    @PostMapping
    public ResponseEntity<Pet> createPet(@RequestBody Pet pet) {
        return ResponseEntity.ok(petService.save(pet));
    }
}

package com.petclinic.pet;

import org.springframework.data.jpa.repository.JpaRepository;

public interface PetRepository extends JpaRepository<Pet, Long> {
}

package com.petclinic.pet;

import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class PetService {

    private final PetRepository petRepository;

    public PetService(PetRepository petRepository) {
        this.petRepository = petRepository;
    }

    public Pet findById(Long id) {
        return petRepository.findById(id)
            .orElseThrow(() -> new RuntimeException("Pet not found"));
    }

    @Transactional
    public Pet save(Pet pet) {
        return petRepository.save(pet);
    }
}

package com.petclinic.pet;

import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;
import com.fasterxml.jackson.databind.ObjectMapper;

import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@SpringBootTest
@AutoConfigureMockMvc
class PetControllerIntegrationTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @Autowired
    private PetService petService;

    @Test
    void shouldCreateAndRetrievePet() throws Exception {
        Pet pet = new Pet();
        pet.setName("Buddy");
        pet.setOwnerName("Alice");

        // Create pet
        String createdPetJson = mockMvc.perform(post("/api/pets")
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(pet)))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$.name").value("Buddy"))
            .andExpect(jsonPath("$.ownerName").value("Alice"))
            .andReturn().getResponse().getContentAsString();

        Pet createdPet = objectMapper.readValue(createdPetJson, Pet.class);

        // Retrieve pet
        mockMvc.perform(get("/api/pets/" + createdPet.getId()))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$.name").value("Buddy"))
            .andExpect(jsonPath("$.ownerName").value("Alice"));
    }

    @Test
    void shouldReturn404WhenPetNotFound() throws Exception {
        mockMvc.perform(get("/api/pets/999"))
            .andExpect(status().isInternalServerError());
    }
}

