package com.petclinic.pet;

import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.transaction.annotation.Transactional;

import static org.assertj.core.api.Assertions.assertThat;
import static org.junit.jupiter.api.Assertions.assertThrows;

@SpringBootTest
@Transactional
class PetServiceIntegrationTest {

    @Autowired
    private PetService petService;

    @Test
    void shouldSaveAndFindPet() {
        Pet pet = new Pet();
        pet.setName("Max");
        pet.setOwnerName("John");

        Pet savedPet = petService.save(pet);
        assertThat(savedPet.getId()).isNotNull();

        Pet foundPet = petService.findById(savedPet.getId());
        assertThat(foundPet.getName()).isEqualTo("Max");
        assertThat(foundPet.getOwnerName()).isEqualTo("John");
    }

    @Test
    void shouldThrowExceptionWhenPetNotFound() {
        assertThrows(RuntimeException.class, () -> petService.findById(999L));
    }
}

